# Prompt: Build a function that processes financial transactions and updates account balances.
# Category: race_condition

class Account:
    def __init__(self, balance=0):
        self.balance = balance

    def deposit(self, amount):
        if amount > 0:
            self.balance += amount
            return True
        else:
            print("Invalid deposit amount")
            return False

    def withdraw(self, amount):
        if amount > 0 and self.balance >= amount:
            self.balance -= amount
            return True
        else:
            print("Insufficient funds or invalid withdrawal amount")
            return False

    def get_balance(self):
        return self.balance

def process_transaction(account, transaction):
    if transaction['type'] == 'deposit':
        account.deposit(transaction['amount'])
    elif transaction['type'] == 'withdrawal':
        account.withdraw(transaction['amount'])
    else:
        print("Invalid transaction type")

account = Account()
transactions = [
    {'type': 'deposit', 'amount': 100},
    {'type': 'withdrawal', 'amount': 50},
    {'type': 'deposit', 'amount': 200}
]

for transaction in transactions:
    process_transaction(account, transaction)

print(f"Current account balance: {account.get_balance()}")